async (params, browser) => {
  // Open Spotify Web Player
  await browser.open('https://open.spotify.com/')

  // Wait for Spotify to load
  await browser.waitForSelector('[data-testid="rootlist-item"], [data-testid="create-playlist-button"], nav', 15000)

  // Let Spotify fully initialize
  await browser.wait(2000)

  // Create playlist via Spotify API
  const create_result = await browser.evaluate(`let accessToken = ''; try { const tokenEl = document.querySelector('script#session, script[id*="session"]'); if (tokenEl) { const data = JSON.parse(tokenEl.textContent); accessToken = data.accessToken || ''; } } catch(e) {} if (!accessToken) { try { const cookies = document.cookie.split(';'); for (const c of cookies) { if (c.trim().startsWith('sp_t=') || c.trim().startsWith('sp_dc=')) { accessToken = c.trim().split('=')[1]; } } } catch(e) {} } if (!accessToken) { try { const tokenResp = await fetch('https://open.spotify.com/get_access_token?reason=transport&productType=web_player', { credentials: 'include' }); const tokenData = await tokenResp.json(); accessToken = tokenData.accessToken || ''; } catch(e) {} } if (!accessToken) { return { success: false, message: 'Could not retrieve Spotify access token. Please ensure you are logged in to Spotify Web Player.' }; } let userId = ''; try { const meResp = await fetch('https://api.spotify.com/v1/me', { headers: { 'Authorization': 'Bearer ' + accessToken } }); const meData = await meResp.json(); userId = meData.id || ''; } catch(e) { return { success: false, message: 'Could not fetch user profile. Token may be expired.' }; } const playlistDesc = '' + params.description + '' || ''; try { const resp = await fetch('https://api.spotify.com/v1/users/' + userId + '/playlists', { method: 'POST', headers: { 'Authorization': 'Bearer ' + accessToken, 'Content-Type': 'application/json' }, body: JSON.stringify({ name: '' + params.name + '', description: playlistDesc, public: false }) }); const data = await resp.json(); if (data.id) { return { success: true, playlist_id: data.id, playlist_name: data.name, playlist_url: data.external_urls ? data.external_urls.spotify : 'https://open.spotify.com/playlist/' + data.id, owner: userId }; } else { return { success: false, message: 'Failed to create playlist', error: JSON.stringify(data) }; } } catch(e) { return { success: false, message: e.message }; }`)

  return create_result
}
